export const classifyError = (error: unknown): { type: string; message: string } => {
    let errorMessage: string;

    if (typeof error === "object" && error !== null) {
      if ("message" in error) {
        errorMessage = (error as Error).message;
      } else {
        errorMessage = "Unknown error";  
      }
    } else {
      errorMessage = error?.toString() || "Unknown error";
    }

    const businessErrors = [
      "Customer not found",
      "Contracted product not found",
      "Promoção já contratada para o cliente",
    ];

    if (businessErrors.some((msg) => errorMessage.includes(msg))) {
      return { type: "business", message: errorMessage };
    }

    if (errorMessage.includes("Erro na consulta da query") || errorMessage.includes("status: -1")) {
      return { type: "system", message: errorMessage };
    }

    return { type: "system", message: errorMessage };
  };

