import { GraphQlService } from "libAppCommons";
import { OrderServiceSave } from "../infrastructure/index";
import { ContractedProductFilterResponse, PostPromotionResponse } from "../models/index";

export class PostPromotion {
  constructor(private readonly graphQlService: GraphQlService) {}

  async execute(
    nrc: string,
    accessPoint: string,
    companyIdentification: string
  ): Promise<PostPromotionResponse> {
    const date = new Date().toISOString().split("T")[0] + "T01:00:00";
    const parameters = [nrc, companyIdentification, date, accessPoint];

    try {
      const serviceResponse: ContractedProductFilterResponse =
      await this.graphQlService.executeQuery(
        process.env.NST_BILLING_ORDER_URL!,
        process.env.NST_BILLING_PORT!,
        OrderServiceSave,
        parameters,
        process.env.NST_BILLING_PATH!
      );
      if (serviceResponse.status === -1) {

        const message = serviceResponse.data.message;

        const match = message?.match(/code\s*:\s*["“”]([A-Z0-9_-]+)["“”]/);
        const faultCode = match ? match[1] : null;

        if (faultCode === "OMA-ERR_00496") {
          return {
            status: 0,
            message: "Promoção já contratada para o cliente.",
          };
        }

        throw new Error(message || "Erro na consulta da query");
      }

      return {
        status: 0,
        message: "Promoção contratada com sucesso.",
      };


    } catch (err) {
      throw new Error(String('BillingProductService.OrderServiceSave' + err));
    }
  }
}

