### 4.4 Implement Secrets Rotation Lambda
```typescript
// Secrets Manager Rotation Function
export async function rotateHMACSecret(event: RotationEvent) {
  const { Step, Token, SecretId } = event;

  switch (Step) {
    case 'createSecret':
      // Generate new HMAC key
      const newKey = crypto.randomBytes(32).toString('base64');
      const secret = await getSecretValue(SecretId);
      const parsed = JSON.parse(secret.SecretString);

      const nextVersion = `v${parseInt(parsed.current.substring(1)) + 1}`;
      parsed.versions[nextVersion] = {
        keyId: nextVersion,
        keyValue: newKey,
        createdAt: new Date().toISOString(),
        status: 'ACTIVE'
      };

      await putSecretValue(SecretId, Token, JSON.stringify(parsed));
      break;

    case 'setSecret':
      // Update current pointer
      const currentSecret = await getSecretValue(SecretId, Token);
      const current = JSON.parse(currentSecret.SecretString);
      const versions = Object.keys(current.versions);
      current.current = versions[versions.length - 1];

      await putSecretValue(SecretId, Token, JSON.stringify(current));
      break;

    case 'testSecret':
      // Verify new version works
      const testSecret = await getSecretValue(SecretId, Token);
      const testParsed = JSON.parse(testSecret.SecretString);
      const testCPF = '11122233344';
      const token = hmacSha256(testCPF, testParsed.versions[testParsed.current].keyValue);
      if (!token) throw new Error('HMAC generation failed');
      break;

    case 'finishSecret':
      // Mark old versions for deletion after TTL
      const finalSecret = await getSecretValue(SecretId, Token);
      const finalParsed = JSON.parse(finalSecret.SecretString);

      Object.entries(finalParsed.versions).forEach(([id, version]: [string, any]) => {
        if (id !== finalParsed.current) {
          const age = Date.now() - new Date(version.createdAt).getTime();
          if (age > 90 * 24 * 60 * 60 * 1000) {  // 90 days
            version.status = 'PENDING_DELETION';
          }
        }
      });

      await finishSecret(SecretId, Token);
      break;
  }
}
```

